char *substr(const char *str, int start, int end) {
    // 开辟一个字符串去存储我们的数据，开辟多大计算
    // char sub[end -start];
    int len = end - start;
    if (len == 0) {
        return nullptr;
    }
    char *sub = (char *) malloc(sizeof(char) * (len + 1));// 记得+1，因为还有一个\0，在 NDK 一般会采用静态的数组存储 char sub[len]
    // malloc 一定要 free

