## 2.4 层序遍历

```c++
template <class T>
void levelOrderTraverse(TreeNode<T> *pNode,void(*visit)(T)){
    if(!pNode)
        return;

    queue<TreeNode<T>*> queue;
    queue.push(pNode);
    while(!queue.empty()){
        TreeNode<T> *front = queue.front();
        queue.pop();
        visit(front->data);

        if(front->left)
            queue.push(front->left);

        if(front->right)
            queue.push(front->right);
    }
}
