            lowcost[minId] = 0;
            sum += min;

            for (int k = 0; k < vertexSize; k++) {
                // 边考虑边淘汰
                if(matrix[minId][k] < lowcost[k] && lowcost[k] > 0){
                    lowcost[k] = matrix[minId][k];
                }
